+/**
+ * Filter populate fields based on user field-level permissions
+ * Prevents unauthorized field population (CVE-2023-48218)
+ * @param {Object} user - The authenticated user
+ * @param {Object|string} populate - The populate configuration
+ * @param {Object} contentType - The content type being accessed
+ * @returns {Object} - Filtered populate configuration
+ */
+function filterPopulateByPermissions(user, populate, contentType) {
+  if (!populate || typeof populate !== 'object') {
+    return populate;
+  }
+
+  const filteredPopulate = {};
+  const service = getService('permissions');
+
+  for (const [field, fieldPopulate] of Object.entries(populate)) {
+    // Check if user has permission to access this field
+    const hasPermission = service.hasFieldPermission(
+      user,
+      contentType,
+      field
+    );
+
+    if (hasPermission) {
+      // Recursively filter nested populate
+      filteredPopulate[field] = filterPopulateByPermissions(
+        user,
+        fieldPopulate,
+        contentType
+      );
+    }
+  }
+
+  return Object.keys(filteredPopulate).length > 0 ? filteredPopulate : null;
+}
