@@ -0,0 +1,35 @@
+import { RemotePattern } from './image-config'
+
+/**
+ * Validates if a hostname matches a remote pattern configuration
+ * This prevents arbitrary external image sources from being used
+ */
+export function isAllowedRemotePattern(
+  hostname: string,
+  pattern: RemotePattern
+): boolean {
+  const { hostname: patternHostname, pathname, protocol, port } = pattern
+
+  // Validate protocol if specified
+  if (protocol && protocol !== 'http' && protocol !== 'https') {
+    return false
+  }
+
+  // Validate hostname pattern
+  if (patternHostname) {
+    const patternHostnameLower = patternHostname.toLowerCase()
+    const hostnameLower = hostname.toLowerCase()
+
+    // Support wildcard patterns
+    if (patternHostnameLower.startsWith('*.') && !hostnameLower.endsWith(patternHostnameLower.substring(1))) {
+      return false
+    } else if (patternHostnameLower !== hostnameLower && !hostnameLower.endsWith(`.${patternHostnameLower}`)) {
+      return false
+    }
+  }
+
+  // Validate pathname pattern if specified
+  if (pathname) {
+    const pathnameLower = pathname.toLowerCase()
+    const pathLower = hostname.toLowerCase()
+    if (!pathLower.includes(pathnameLower)) {
+      return false
+    }
+  }
+
+  return true
+}
